/// Generate a launchd plist XML string.
pub fn generate_launchd_plist(
    moltis_bin: &Path,
    _config: &ServiceConfig,
    log_path: &Path,
) -> String {
    let bin = moltis_bin.display();
    let log = log_path.display();

    let args = [
        format!("    <string>{bin}</string>"),
        "    <string>node</string>".to_string(),
        "    <string>run</string>".to_string(),
    ];

    let args_str = args.join("\n");

    format!(
        r#"<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
  <key>Label</key>
  <string>{LAUNCHD_LABEL}</string>
  <key>ProgramArguments</key>
  <array>
{args_str}
  </array>
  <key>RunAtLoad</key>
  <true/>
  <key>KeepAlive</key>
  <dict>
    <key>SuccessfulExit</key>
    <false/>
  </dict>
  <key>ThrottleInterval</key>
  <integer>10</integer>
  <key>StandardOutPath</key>
  <string>{log}</string>
  <key>StandardErrorPath</key>
  <string>{log}</string>
  <key>ProcessType</key>
  <string>Background</string>
</dict>
</plist>
"#
    )
}

fn install_launchd(
    moltis_bin: &Path,
    config: &ServiceConfig,
    log_path: &Path,
) -> anyhow::Result<()> {
    let plist_path = launchd_plist_path()?;

    // Unload first if already loaded (ignore errors).
    let _ = Command::new("launchctl")
        .args([
            "bootout",
            &format!("gui/{}", uid()),
            plist_path.to_str().unwrap_or_default(),
        ])
        .output();

    let plist = generate_launchd_plist(moltis_bin, config, log_path);

    if let Some(parent) = plist_path.parent() {
        fs::create_dir_all(parent)?;
    }
    fs::write(&plist_path, &plist)?;
    info!(path = %plist_path.display(), "wrote launchd plist");

    let output = Command::new("launchctl")
        .args([
            "bootstrap",
            &format!("gui/{}", uid()),
            plist_path.to_str().unwrap_or_default(),
        ])
        .output()?;

