	if (!id) return;
	setName(id.name || "");
	setEmoji(id.emoji || "");
	setTheme(id.theme || "");
	setUserName(id.user_name || "");
	setSoul(id.soul || "");
}, [id]);

var savedTimerRef = useRef(null);
function flashSaved() {
	if (savedTimerRef.current) clearTimeout(savedTimerRef.current);
	setSaved(true);
	savedTimerRef.current = setTimeout(() => {
		savedTimerRef.current = null;
		setSaved(false);
		rerender();
	}, 2000);
}

if (loading.value) {
	return html`<div class="flex-1 flex flex-col min-w-0 p-4 gap-4 overflow-y-auto">
		<div class="text-xs text-[var(--muted)]">Loading\u2026</div>
	</div>`;
}

function onSave(e) {
	e.preventDefault();
	var v = validateIdentityFields(name, userName);
	if (!v.valid) {
		setError(v.error);
		return;
	}
	setError(null);
	setSaving(true);
	setSaved(false);

	updateIdentity(
		{
			name: name.trim(),
			emoji: emoji.trim() || "",
			theme: theme.trim() || "",
			soul: soul.trim() || null,
			user_name: userName.trim(),
		},
		{ agentId: "main" },
	).then((res) => {
		setSaving(false);
		if (res?.ok) {
			identity.value = res.payload;
			gon.set("identity", res.payload);
			refreshGon();
			var emojiChanged = (emoji.trim() || "") !== (id?.emoji || "").trim();
			setShowFaviconReloadHint(emojiChanged && isSafariBrowser());
			flashSaved();
		} else {
			setError(res?.error?.message || "Failed to save");
		}
		rerender();
	});
}

