/// Generate a launchd plist XML string.
///
/// `node run` reads connection parameters from `~/.moltis/node.json` at
/// runtime, so only `--timeout` is passed as a CLI flag here.
pub fn generate_launchd_plist(
    moltis_bin: &Path,
    config: &ServiceConfig,
    log_path: &Path,
) -> String {
    let bin = moltis_bin.display();
    let log = log_path.display();

    let mut args = vec![
        format!("    <string>{bin}</string>"),
        "    <string>node</string>".to_string(),
        "    <string>run</string>".to_string(),
        "    <string>--timeout</string>".to_string(),
        format!("    <string>{}</string>", config.timeout),
    ];

    // Environment variables for values that `node run` reads from
    // `node.json` — included in the plist so launchd's env inherits them
    // and they can be inspected via `launchctl print`.
    let mut env_vars = vec![
        ("MOLTIS_NODE_GATEWAY_URL", config.gateway_url.as_str()),
        ("MOLTIS_NODE_DEVICE_TOKEN", config.device_token.as_str()),
    ];
    if let Some(ref id) = config.node_id {
        env_vars.push(("MOLTIS_NODE_ID", id.as_str()));
    }
    if let Some(ref name) = config.display_name {
        env_vars.push(("MOLTIS_NODE_DISPLAY_NAME", name.as_str()));
    }
    if let Some(ref dir) = config.working_dir {
        args.push("    <string>--working-dir</string>".to_string());
        args.push(format!("    <string>{dir}</string>"));
