///
/// `callback` must be a valid function pointer that remains valid for
/// the lifetime of the process.
#[allow(unsafe_code)]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn moltis_set_network_audit_callback(callback: NetworkAuditCallback) {
