                        .and_then(|e| e.get("key"))
                        .and_then(|k| k.as_str())
                {
                    broadcast(
                        &ctx.state,
                        "session",
                        serde_json::json!({
                            "kind": "created",
                            "sessionKey": key,
                        }),
                        BroadcastOpts {
                            drop_if_slow: true,
