                broadcast(
                    &ctx.state,
                    "skills.install.progress",
                    serde_json::json!({
                        "phase": "start",
                        "source": source,
                        "op_id": op_id,
                    }),
                    BroadcastOpts::default(),
                )
                .await;

                match ctx.state.services.skills.install(ctx.params.clone()).await {
                    Ok(payload) => {
                        broadcast(
                            &ctx.state,
                            "skills.install.progress",
                            serde_json::json!({
